INSERT OR IGNORE INTO questions (id, category_id, stem, options_json, answer, explanation, difficulty) VALUES
(101,1,'习近平新时代中国特色社会主义思想明确，中国特色社会主义最本质的特征是：','[{"label":"A","content":"中国共产党领导"},{"label":"B","content":"人民当家作主"},{"label":"C","content":"依法治国"},{"label":"D","content":"改革开放"}]','A','中国共产党领导是中国特色社会主义最本质的特征，也是中国特色社会主义制度的最大优势。','基础'),
(102,1,'实践之所以成为检验真理的唯一标准，是因为实践具有：','[{"label":"A","content":"社会历史性"},{"label":"B","content":"直接现实性"},{"label":"C","content":"主观能动性"},{"label":"D","content":"客观普遍性"}]','B','实践能够把主观认识同客观实际联系起来，并把主观认识转化为直接现实。','基础'),
(103,1,'新发展理念中，引领发展的第一动力是：','[{"label":"A","content":"协调"},{"label":"B","content":"绿色"},{"label":"C","content":"开放"},{"label":"D","content":"创新"}]','D','创新是引领发展的第一动力。','基础'),
(104,1,'我国的根本政治制度是：','[{"label":"A","content":"人民代表大会制度"},{"label":"B","content":"基层群众自治制度"},{"label":"C","content":"民族区域自治制度"},{"label":"D","content":"多党合作制度"}]','A','人民代表大会制度是我国的根本政治制度。','基础'),
(105,1,'唯物辩证法认为，事物发展的根本原因在于事物的：','[{"label":"A","content":"外部环境"},{"label":"B","content":"内部矛盾"},{"label":"C","content":"发展阶段"},{"label":"D","content":"历史条件"}]','B','内因是事物变化发展的根据。','进阶'),
(201,2,'根据我国宪法，下列哪一项属于公民的基本义务？','[{"label":"A","content":"参加选举"},{"label":"B","content":"依法纳税"},{"label":"C","content":"获得物质帮助"},{"label":"D","content":"提出建议"}]','B','依法纳税是公民的基本义务。','基础'),
(202,2,'“但愿人长久，千里共婵娟”中的“婵娟”指的是：','[{"label":"A","content":"桂花"},{"label":"B","content":"月亮"},{"label":"C","content":"女子"},{"label":"D","content":"云彩"}]','B','此处“婵娟”指明月。','基础'),
(203,2,'下列现象中，属于光的折射的是：','[{"label":"A","content":"水中倒影"},{"label":"B","content":"小孔成像"},{"label":"C","content":"雨后彩虹"},{"label":"D","content":"月食形成"}]','C','彩虹与光的折射、反射和色散有关。','基础'),
(204,2,'我国面积最大的淡水湖是：','[{"label":"A","content":"洞庭湖"},{"label":"B","content":"鄱阳湖"},{"label":"C","content":"太湖"},{"label":"D","content":"洪泽湖"}]','B','鄱阳湖是我国面积最大的淡水湖。','基础'),
(205,2,'作出责令停产停业的处罚前，应告知当事人有要求举行什么的权利？','[{"label":"A","content":"复议"},{"label":"B","content":"听证"},{"label":"C","content":"仲裁"},{"label":"D","content":"调解"}]','B','当事人依法享有要求听证的权利。','进阶'),
(301,3,'传统风貌与现代生活应当如何相处？','[{"label":"A","content":"相得益彰"},{"label":"B","content":"分庭抗礼"},{"label":"C","content":"背道而驰"},{"label":"D","content":"泾渭分明"}]','A','相得益彰指互相配合，使双方优点更充分地显现。','基础'),
(302,3,'阅读文章不仅要记结论，更要理解作者如何提出问题、组织证据。这强调阅读应：','[{"label":"A","content":"扩大数量"},{"label":"B","content":"关注论证过程"},{"label":"C","content":"记忆观点"},{"label":"D","content":"选择经典"}]','B','文段强调理解作者的思考和论证过程。','基础'),
(303,3,'基层治理既要有统筹全局的____，也要有解决小事的____。','[{"label":"A","content":"视野 耐心"},{"label":"B","content":"眼光 魄力"},{"label":"C","content":"能力 技巧"},{"label":"D","content":"规划 速度"}]','A','搭配和语义均以“视野、耐心”最恰当。','基础'),
(304,3,'古籍数字化语句排序正确的是：②古籍损坏 ①提供保存手段 ③不等于完成传承 ④还需整理阐释。','[{"label":"A","content":"②①③④"},{"label":"B","content":"①②④③"},{"label":"C","content":"②③①④"},{"label":"D","content":"①③②④"}]','A','先提出问题，再给出手段，之后转折并说明不足。','基础'),
(305,3,'治愈内容提供安慰，但也不能回避现实问题。最适合的标题是：','[{"label":"A","content":"情绪消费成为潮流"},{"label":"B","content":"治愈之外还需面对现实"},{"label":"C","content":"轻盈表达受欢迎"},{"label":"D","content":"网络内容拒绝娱乐"}]','B','标题应覆盖转折后的核心观点。','进阶'),
(401,4,'120人按1至120编号。偶数编号者向后转，5的倍数者再向后转。面向前方者编号总和为：','[{"label":"A","content":"1500"},{"label":"B","content":"1560"},{"label":"C","content":"3600"},{"label":"D","content":"3660"}]','D','最终面向前方的是转动0次或2次的人，计算得3660。','挑战'),
(402,4,'甲、乙两数之和为48，甲数比乙数多25%，则甲数为：','[{"label":"A","content":"24"},{"label":"B","content":"26"},{"label":"C","content":"80/3"},{"label":"D","content":"30"}]','C','设乙为x，则2.25x=48，甲为80/3。','基础'),
(403,4,'甲单独完成工程需12天，乙需18天。合作3天后，剩余由甲完成，还需几天？','[{"label":"A","content":"5"},{"label":"B","content":"6"},{"label":"C","content":"7"},{"label":"D","content":"8"}]','C','合作3天完成5/12，剩余7/12由甲完成需7天。','基础'),
(404,4,'从1、2、3、4、5中任取两个不同的数，和为偶数的概率是：','[{"label":"A","content":"2/5"},{"label":"B","content":"1/2"},{"label":"C","content":"3/5"},{"label":"D","content":"4/5"}]','A','同奇偶组合共4种，总组合10种，概率2/5。','基础'),
(405,4,'某商品先提价20%，再打八折出售，现价与原价相比：','[{"label":"A","content":"降低4%"},{"label":"B","content":"不变"},{"label":"C","content":"提高4%"},{"label":"D","content":"降低2%"}]','A','1.2×0.8=0.96，降低4%。','基础'),
(501,5,'某地区去年生产总值800亿元，今年增长6.25%。今年为多少亿元？','[{"label":"A","content":"825"},{"label":"B","content":"840"},{"label":"C","content":"850"},{"label":"D","content":"860"}]','C','800×1.0625=850亿元。','基础'),
(502,5,'新能源汽车销量由12万辆增至15万辆，同比增长约：','[{"label":"A","content":"20%"},{"label":"B","content":"25%"},{"label":"C","content":"30%"},{"label":"D","content":"33.3%"}]','B','(15-12)÷12=25%。','基础'),
(503,5,'某校2000人，其中女生占48%。女生比男生少多少人？','[{"label":"A","content":"40"},{"label":"B","content":"60"},{"label":"C","content":"80"},{"label":"D","content":"100"}]','C','女生960人，男生1040人，相差80人。','基础'),
(504,5,'一季度营收120万元，二季度环比增长15%，三季度环比下降10%。三季度营收为：','[{"label":"A","content":"121.5万元"},{"label":"B","content":"124.2万元"},{"label":"C","content":"126万元"},{"label":"D","content":"138万元"}]','B','120×1.15×0.9=124.2万元。','基础'),
(505,5,'产品出口额增长20%，出口量增长25%，平均出口价格约：','[{"label":"A","content":"下降4%"},{"label":"B","content":"下降5%"},{"label":"C","content":"上涨4%"},{"label":"D","content":"上涨5%"}]','A','1.20÷1.25=0.96，因此下降4%。','进阶');
